import { MovieProfile } from '../movie-profile';
import axios from 'axios';
import { useEffect, useState } from 'react';
import { LoadingPage } from '../loading-page';
import { Link } from 'react-router-dom';
import { formatLanguageToApi } from '../utils/api-utils';
import { useLanguage } from '../../context/language';
import { useTheme } from '../../context/theme';
import { LoadMoreButton } from '../load-more/load-more-button';
import { LANGUAGES } from '../../i18n/translations';

interface ResultType {
	adult: boolean;
	backdrop_path: string;
	genre_ids: Array<number>;
	id: number;
	original_language: string;
	original_title: string;
	overview: string;
	popularity: number;
	poster_path: string;
	release_date: string;
	title: string;
	video: boolean;
	vote_average: number;
	vote_count: number;
}

export interface MoviesInformation {
	page?: number;
	results: Array<ResultType>;
	total_pages?: number;
	total_results?: number;
	type: string; //not being used for now, but created in an attempt of making the handle load more button a generic function
}

export function HomePage() {
	const [topMovies, setTopMovies] = useState<MoviesInformation>({ results: [], type: '' });
	const [horrorMovies, setHorrorMovies] = useState<MoviesInformation>({ results: [], type: '' });
	const [animationMovies, setAnimationMovies] = useState<MoviesInformation>({ results: [], type: '' });
	const [isLoading, setIsLoading] = useState(false);
	const [topMoviesGridVisibility, setTopMoviesGridVisibility] = useState(false);
	const [horrorMoviesGridVisibility, setHorrorMoviesGridVisibility] = useState(false);
	const [animationMoviesGridVisibility, setAnimationMoviesGridVisibility] = useState(false);

	const { language } = useLanguage();
	const { theme } = useTheme();

	const token = `Bearer ${process.env.REACT_APP_TMDB_BEARER_TOKEN}`;
	const topMoviesUrl = `https://api.themoviedb.org/3/movie/top_rated?api_key=${process.env.REACT_APP_TMDB_API_KEY}&language=${formatLanguageToApi(language)}`;
	const horrorMoviesUrl = `https://api.themoviedb.org/3/discover/movie?with_genres=27&api_key=${process.env.REACT_APP_TMDB_API_KEY}&language=${formatLanguageToApi(language)}`;
	const animationMoviesUrl = `https://api.themoviedb.org/3/discover/movie?with_genres=16&api_key=${process.env.REACT_APP_TMDB_API_KEY}&language=${formatLanguageToApi(language)}`;

	async function getTopMovieData() {
		setIsLoading(true);
		const topMoviesResponse = await axios({
			method: 'get',
			url: topMoviesUrl,
			headers: { Authorization: token }
		});
		setTopMovies({ ...topMoviesResponse.data, type: 'topMovies' });

		const horrorMoviesResponse = await axios({
			method: 'get',
			url: horrorMoviesUrl,
			headers: { Authorization: token }
		});
		setHorrorMovies({ ...horrorMoviesResponse.data, type: 'horrorMovies' });

		const animationMoviesResponse = await axios({
			method: 'get',
			url: animationMoviesUrl,
			headers: { Authorization: token }
		});
		setAnimationMovies({ ...animationMoviesResponse.data, type: 'animationMovies' });

		setIsLoading(false);
	}

	function renderGrid(index: number, movie: any, gridVisibility: boolean) {
		switch (true) {
		case index < 4:
		case index >= 4 && gridVisibility === true:
			return (
				<Link to={`/movie/${movie.id}`} key={movie.id} accessKey="abc">
					<MovieProfile pictureUrl={`https://image.tmdb.org/t/p/w500${movie.poster_path}`} title={movie.title} releaseDate={movie.release_date} />
				</Link>
			);
		}
	}

	function handleSeeMoreTopButton() {
		switch (topMoviesGridVisibility) {
		case false:
			setTopMoviesGridVisibility(true);
			break;
		case true:
			setTopMoviesGridVisibility(false);
			break;
		}
	}

	function handleSeeMoreHorrorButton() {
		switch (horrorMoviesGridVisibility) {
		case false:
			setHorrorMoviesGridVisibility(true);
			break;
		case true:
			setHorrorMoviesGridVisibility(false);
			break;
		}
	}

	function handleSeeMoreAnimationButton() {
		switch (animationMoviesGridVisibility) {
		case false:
			setAnimationMoviesGridVisibility(true);
			break;
		case true:
			setAnimationMoviesGridVisibility(false);
			break;
		}
	}

	useEffect(() => {
		getTopMovieData();
	}, [language]);

	return (
		<div className={`${theme.themeBgClassName} ${theme.themeTextClassName} h-100`}>
			{isLoading ? (
				<LoadingPage />
			) : (
				<>
					<div className="bg-[url('/Users/denzelwallace/Desktop/Me/Estudos/React/dmdb-app/public/assets/background.jpg')] bg-cover backdrop-blur-3xl bg-center text-center p-72">
						<p className="text-9xl font-extrabold text-white">DMDB</p>
						<p className="text-2xl text-white"> {LANGUAGES[language].homePageSubtitle}</p>
					</div>
					<div className="grid grid-cols-4 gap-9 object-cover p-7 pt-3">
						{topMovies.results.map((movie: ResultType, index) => {
							return renderGrid(index, movie, topMoviesGridVisibility);
						})}
					</div>
					<div className="flex h-10">{LoadMoreButton(theme, handleSeeMoreTopButton, topMoviesGridVisibility)}</div>
					<div className="grid grid-cols-4 gap-9 object-cover p-7 pt-3">
						{animationMovies.results.map((movie: ResultType, index) => {
							return renderGrid(index, movie, animationMoviesGridVisibility);
						})}
					</div>
					<div className="flex h-10">{LoadMoreButton(theme, handleSeeMoreAnimationButton, animationMoviesGridVisibility)}</div>
					<div className="grid grid-cols-4 gap-9 object-cover p-7 pt-3">
						{horrorMovies.results.map((movie: ResultType, index) => {
							return renderGrid(index, movie, horrorMoviesGridVisibility);
						})}
					</div>
					<div className="flex h-10">{LoadMoreButton(theme, handleSeeMoreHorrorButton, horrorMoviesGridVisibility)}</div>
				</>
			)}
		</div>
	);
}
